# Spell Book

def fireball(target):
    damage = 40
    print(f"{target} takes {damage}")
    return damage

def ice_wall(duration):
    print(f"Wall lasts {duration}s")
    return True

def heal(target, amount):
    target.hp += amount
    print(f"Healed {amount} HP")

def lightning(targets):
    for t in targets:
        print(f"Zap! {t} stunned")

def shield(caster):
    caster.armor += 10
    print("Shield up!")

def teleport(x, y):
    print(f"Warped to ({x}, {y})")
    return (x, y)

def summon(creature):
    print(f"{creature} appears!")
    return creature

def curse(target):
    target.speed -= 5
    print(f"{target} slowed!")
